import { describe, it } from 'node:test';
import assert from 'node:assert/strict';

import safe from '../index.js';
import os from 'node:os';
import path from 'node:path';
import crypto from 'node:crypto';
import url from 'node:url';

describe('JSON', function () {
    it('should not throw error when parsing bad JSON', function () {
        const json = safe.JSON.parse('This is totally { not json }');
        assert.strictEqual(json, null);
        assert.notStrictEqual(safe.error, null);
    });

    it('should clear error when parsing good JSON', function () {
        const json = safe.JSON.parse('{ "totally" : "json" }');
        assert.strictEqual(json.totally, 'json');
        assert.strictEqual(safe.error, null);
    });

    it('should not throw error when stringifying bad object', function () {
        const obj = { };
        obj.a = { b: obj }; // circular reference
        const str = safe.JSON.stringify(obj);
        assert.strictEqual(str, null);
        assert.notStrictEqual(safe.error, null);
    });
});

describe('CSV', function () {
    it('can parse CSV', function () {
        const result = safe.CSV.parse('one,2,true\nfour,5,false', 'h1:string', 'h2:number', 'h3:boolean');
        assert.deepStrictEqual(result, [
            { h1: 'one', h2: 2, h3: true },
            { h1: 'four', h2: 5, h3: false }
        ]);
    });

    it('ignores extra fields not in header', function () {
        const result = safe.CSV.parse('one,two,three,four', 'h1:string', 'h2:string', 'h3:string');
        assert.deepStrictEqual(result, [
            { h1: 'one', h2: 'two', h3: 'three' },
        ]);
    });

    it('ignores missing fields not in header', function () {
        const result = safe.CSV.parse('one,two', 'h1:string', 'h2:string', 'h3:string');
        assert.deepStrictEqual(result, [
            { h1: 'one', h2: 'two' },
        ]);
    });

    it('ignores fields not matching type', function () {
        const result = safe.CSV.parse('one,two,three,four', 'h1:string', 'h2:number', 'h3:boolean');
        assert.deepStrictEqual(result, [
            { h1: 'one' },
        ]);
    });
});

describe('fs', function () {
    it('should not throw error when reading non-existent file', function () {
        const fileContents = safe.fs.readFileSync('RANDOM');
        assert.strictEqual(fileContents, null);
    });
    it('should not throw on creating existing dir', function () {
        assert.strictEqual(safe.fs.mkdirSync(os.tmpdir()), false);
        assert.notStrictEqual(safe.error, null); // EEXIST
    });
    it('should return true for creating dir', function () {
        const tmpdirname = 'safetydance-test-' + crypto.randomBytes(4).readUInt32LE(0);
        const tmpdir = path.resolve(os.tmpdir(), tmpdirname);
        assert.strictEqual(safe.fs.mkdirSync(tmpdir), true);
    });
    it('should return true for removing files', function () {
        const tmpfile = path.join(os.tmpdir(), 'safetydance-test-' + crypto.randomBytes(4).readUInt32LE(0));
        safe.fs.writeFileSync(tmpfile, 'whatever');
        assert.strictEqual(safe.fs.unlinkSync(tmpfile), true);
    });
    it('should not throw when unlinking missing file', function () {
        assert.strictEqual(safe.fs.unlinkSync('/this/is'), false);
    });
    it('should not throw when trying to create existing file', function () {
        assert.strictEqual(safe.fs.openSync('/tmpx'), -1);
    });
    it('should open temp files', function () {
        assert.notStrictEqual(safe.fs.openSync('/tmp/amazing', 'w'), -1);
    });
    it('should not throw when closing non-existent fd', function () {
        assert.strictEqual(safe.fs.closeSync(1242), 0);
    });
    it('should list files', function () {
        assert.ok(Array.isArray(safe.fs.readdirSync(import.meta.dirname)));
    });
    it('should return null when listing non existing dir', function () {
        assert.strictEqual(safe.fs.readdirSync(import.meta.dirname + '/thiscannotbe'), null);
    });
    it('show not throw when chmod of non-existent file', function () {
        assert.strictEqual(safe.fs.chmodSync('/tmp/blah', '600'), false);
    });
    it('show not throw when reading link of non-existent file', function () {
        assert.strictEqual(safe.fs.readlinkSync('/tmp/blah'), null);
    });
    it('show not throw when resolving link of non-existent file', function () {
        assert.strictEqual(safe.fs.realpathSync('/tmp/blah'), null);
    });
    it('should return true for removing dir', function () {
        const tmpdir = path.join(os.tmpdir(), 'safetydance-test-' + crypto.randomBytes(4).readUInt32LE(0));
        safe.fs.mkdirSync(tmpdir);
        assert.strictEqual(safe.fs.rmdirSync(tmpdir), true);
    });
    it('should not throw when removing missing dir', function () {
        assert.strictEqual(safe.fs.rmdirSync('/this/cannot/possibly/exist'), false);
    });
    it('should not throw when trying to stat non-existent file', function () {
        assert.strictEqual(safe.fs.statSync('/tmp/whatever'), null);
    });
    it('should not throw when trying to lstat non-existent file', function () {
        assert.strictEqual(safe.fs.lstatSync('/tmp/whatever'), null);
    });
    it('should lstat existing file', function () {
        assert.ok(safe.fs.lstatSync('/tmp'));
    });
    it('can append to file', function () {
        const fd = safe.fs.openSync('/tmp/append_tester', 'w');
        assert.strictEqual(safe.fs.appendFileSync(fd, 'hello world'), true);
    });
    it('should not throw when trying to chown non-existent file', function () {
        assert.strictEqual(safe.fs.chownSync('/tmp/whatever', 0, 0), false);
    });
});

describe('url', function () {
    it('should not throw for parsing invalid url', function () {
        assert.strictEqual(safe.url.parse(undefined), null);
        assert.strictEqual(safe.url.parse(NaN), null);
        assert.strictEqual(safe.url.parse(43), null);
        assert.strictEqual(safe.url.parse(null), null);
        assert.strictEqual(safe.url.parse({ }), null);
    });

    it('should parse valid urls', function () {
        assert.deepStrictEqual(safe.url.parse('http://www.forwardbias.in'), url.parse('http://www.forwardbias.in'));
    });
});

describe('safeCall', function () {
    it('should call', function () {
        const result = safe.safeCall(function () { return 1 + 2; });
        assert.strictEqual(result, 3);
        assert.strictEqual(safe.error, null);
    });

    it('should return null on exception', function () {
        const result = safe.safeCall(function () { throw new Error('OOPS'); });
        assert.strictEqual(result, null);
        assert.notStrictEqual(safe.error, null);
    });

    it('should set this', function () {
        const obj = { a: 10 };
        const result = safe(function () { return this.a; }.bind(obj));
        assert.strictEqual(result, 10);
        assert.strictEqual(safe.error, null);
    });

    it('should return null if function returns falsy', function () {
        for (const falsyValue of [ null, false, 0, '' ]) {
            const result = safe(function () { return falsyValue; }, 32);
            assert.strictEqual(safe.error, null);
            assert.strictEqual(result, falsyValue);
        }
    });
});

