describe('pick', function () {
    it('picks nothing', function () {
        const data = { x: 10 };
        assert.deepStrictEqual(safe.pick(data, 'no'), {});
        assert.deepStrictEqual(safe.pick(data, 'no:boolean'), {});
    });

    it('picks without types', function () {
        const data = { x: 10, y: 20, z: '30' };
        assert.deepStrictEqual(safe.pick(data, 'z', 'x'), { x: 10, z: '30'});
    });

    it('picks with types', function () {
        const data = { x: 10, y: 20, z: '30', a: true };
        assert.deepStrictEqual(safe.pick(data, 'z:string', 'x:number', 'a'), { a: true, x: 10, z: '30'});
    });

    it('cannot pick with bad types', function () {
        const data = { x: 10, y: 20, z: '30', a: false };
        assert.deepStrictEqual(safe.pick(data, 'x:string'), null);
        assert.ok(safe.error.message.includes('incorrect type'));
        assert.deepStrictEqual(safe.pick(data, 'a:number'), null);
        assert.ok(safe.error.message.includes('incorrect type'));
    });
});

describe('query', function () {
    it('should return self on falsy query', function () {
        const data = { x: 10, y: 20 };
        assert.strictEqual(safe.query(data, ''), data);
        assert.strictEqual(safe.query(data, null), data);
    });

    it('can access top level queries', function () {
        const data = { x: 10, y: 20 };
        assert.strictEqual(safe.query(data, 'x'), 10);
        assert.strictEqual(safe.query(data, '.x'), 10);
        assert.strictEqual(safe.query(data, 'y'), 20);
        assert.strictEqual(safe.query(data, '.y'), 20);
    });

    it('can access nested queries on objects', function () {
        const data = { points: [ { x: 10, y: 20 }, { x: 40, y: 50 } ] };
        assert.strictEqual(safe.query(data, 'points[0].x'), 10);
        assert.strictEqual(safe.query(data, 'points[1].y'), 50);
        assert.strictEqual(safe.query(data, 'points.1.y'), 50);
        assert.strictEqual(safe.query(data, 'points'), data.points);
        assert.strictEqual(safe.query(data, '.points'), data.points);
        assert.strictEqual(safe.query(data, '.points[0]'), data.points[0]);
    });

    it('can access nested queries on arrays', function () {
        const data = [ { x: 10, y: 20 }, { x: 40, y: 50 } ];
        assert.strictEqual(safe.query(data, '[0].x'), 10);
        assert.strictEqual(safe.query(data, '[1].y'), 50);
        assert.strictEqual(safe.query(data, '1.y'), 50);
        assert.strictEqual(safe.query(data, ''), data);
    });

    it('does not throw for bad queries', function () {
        const data = { points: [ { x: 10, y: 20 }, { x: 40, y: 50 } ] };
        assert.strictEqual(safe.query(data, '.'), undefined);
        assert.strictEqual(safe.query(data, 'something'), undefined);
        assert.strictEqual(safe.query(data, 'points[4]'), undefined);
        assert.strictEqual(safe.query(data, 'points[4].random'), undefined);
        assert.strictEqual(safe.query(data, 'points.random'), undefined);
        assert.strictEqual(safe.query(data, 'points.0.well'), undefined);
        assert.strictEqual(safe.query(data, 'points.'), undefined);
        assert.strictEqual(safe.query(data, 'points..'), undefined);
    });

    it('should return defaultValue for bad queries', function () {
        const data = { points: [ { x: 10, y: 20 }, { x: 40, y: 50 } ] };
        const defaultValue = '34';

        assert.strictEqual(safe.query(data, '.', defaultValue), defaultValue);
        assert.strictEqual(safe.query(data, 'something', defaultValue), defaultValue);
        assert.strictEqual(safe.query(data, 'points[4]', defaultValue), defaultValue);
        assert.strictEqual(safe.query(data, 'points[4].random', defaultValue), defaultValue);
        assert.strictEqual(safe.query(data, 'points.random', defaultValue), defaultValue);
        assert.strictEqual(safe.query(data, 'points.0.well', defaultValue), defaultValue);
        assert.strictEqual(safe.query(data, 'points.', defaultValue), defaultValue);
        assert.strictEqual(safe.query(data, 'points..', defaultValue), defaultValue);
    });

    // maybe make these work someday
    it('does not work for keys with .', function () {
        const data = { '0.12': 34 };
        assert.strictEqual(safe.query(data, '0.12'), undefined);
    });
});

describe('set (string)', function () {
    it('can set any level property', function () {
        const obj = { };
        safe.set(obj, 'x', 42);
        assert.strictEqual(obj.x, 42);

        safe.set(obj, 'some.deep.property', 42);
        assert.strictEqual(obj.some.deep.property, 42);
    });

    it('returns new object if source is null', function () {
        let obj = safe.set(null, 'x', 42);
        assert.strictEqual(obj.x, 42);

        obj = safe.set(undefined, 'x', 42);
        assert.strictEqual(obj.x, 42);
    });

    it('deletes non-object properties in path', function () {
        let obj = { some: 42 };
        safe.set(obj, 'some.deep.property', 42);
        assert.strictEqual(obj.some.deep.property, 42);

        obj = 42;
        obj = safe.set(obj, 'some.deep.property', 42);
        assert.strictEqual(obj.some.deep.property, 42);
    });

    it('preserves arrays', function () {
        const obj = { some: [ 34 ] };
        safe.set(obj, 'some[0]', 42);
        assert.strictEqual(obj.some[0], 42);
        assert.strictEqual(obj.some instanceof Array, true);
    });
});

describe('set (array)', function () {
    it('can set any level property', function () {
        const obj = { };
        safe.set(obj, ['x'], 42);
        assert.strictEqual(obj.x, 42);

        safe.set(obj, ['some', 'deep', 'property'], 42);
        assert.strictEqual(obj.some.deep.property, 42);
    });

    it('can have dot in property names', function () {
        const obj = { };
        safe.set(obj, [ '/home/user/code.git' ], 42);
        assert.strictEqual(obj['/home/user/code.git'], 42);
    });
});

describe('unset (string)', function () {
    it('works on non-objects', function () {
        assert.strictEqual(safe.unset(4, 'nice.try'), 4);
        assert.strictEqual(safe.unset(null, 'nice.try'), null);
        assert.strictEqual(safe.unset(undefined, 'nice.try'), undefined);
    });

    it('unsets properties on objects', function () {
        const obj = { x: { y: { z: 34 } } };
        assert.deepStrictEqual(safe.unset(obj, 'x.y.z'), { x: { y: { } } });
        assert.deepStrictEqual(safe.unset(obj, 'x.y'), { x: { } });
        assert.deepStrictEqual(safe.unset(obj, 'x'), { });
        assert.strictEqual(safe.unset(obj, ''), obj);
    });
});

describe('unset (array)', function () {
    it('works on non-objects', function () {
        assert.strictEqual(safe.unset(4, ['nice', 'try']), 4);
    });

    it('unsets properties on objects', function () {
        const obj = { x: { y: { z: 34 } } };
        assert.deepStrictEqual(safe.unset(obj, ['x','y','z']), { x: { y: { } } });
        assert.deepStrictEqual(safe.unset(obj, ['x','y']), { x: { } });
        assert.deepStrictEqual(safe.unset(obj, ['x']), { });
        assert.strictEqual(safe.unset(obj, []), obj);
    });

    it('unsets dot in property names', function () {
        const obj = { };
        obj['/home/user/code.git'] = 42;

        assert.deepStrictEqual(safe.unset(obj, ['/home/user/code.git']), { });
    });
});

describe('require', function () {
    it('returns null for non-existing modules', function () {
        assert.strictEqual(safe.require('momo'), null);
        assert.strictEqual(safe.require('momo.json'), null);
        assert.strictEqual(safe.require('momo', 3), null);
    });

    it('returns module for existing modules', function () {
        assert.ok(safe.require('fs'));
        assert.strictEqual(typeof safe.require('fs').readFile, 'function');
    });
});

describe('child_process', function () {
    it('returns null on invalid execSync command', function () {
        assert.strictEqual(safe.child_process.execSync('blah'), null);
        assert.strictEqual(safe.child_process.execSync('sudo ls', { timeout: 1 }), null);
    });

    it('return stdio on valid execSync command', function () {
        assert.ok(Buffer.isBuffer(safe.child_process.execSync('true')));
        assert.deepStrictEqual(safe.child_process.execSync('cat', { input: 'cloudron' }), Buffer.from('cloudron', 'utf8'));
    });

    it('returns ENOENT on invalid spawnSync command', function () {
        assert.strictEqual(safe.child_process.spawnSync('blah').error.code, 'ENOENT');
        assert.strictEqual(safe.child_process.spawnSync('sudo ls', { timeout: 1 }).error.code, 'ENOENT');
    });

    it('return stdio on valid spawnSync command', function () {
        assert.strictEqual(safe.child_process.spawnSync('true').stdout.length, 0);
        assert.deepStrictEqual(safe.child_process.spawnSync('cat', { input: 'cloudron' }).stdout, Buffer.from('cloudron', 'utf8'));
    });
});

describe('options', function () {
    it('can pass retval in options', function () {
        const retval = safe(function () { throw 'bad'; }, { errorReturnValue: 42 });
        assert.strictEqual(retval, 42);
    });

    it('can pass retval in options (async)', async function () {
        const [error] = await safe(async function () { throw 'bad'; }, { errorReturnValue: 42 });
        assert.strictEqual(error, 'bad');
    });

    it('can pass debug in options', function () {
        let error;
        const printer = (e) => error = e;
        const retval = safe(function () { throw 'bad'; }, { errorReturnValue: 42, debug: printer });
        assert.strictEqual(retval, 42);
        assert.strictEqual(error, 'bad');
    });

    it('can pass debug in options (async)', async function () {
        let error;
        const printer = (e) => error = e;
        const [reterror] = await safe(async function () { throw 'bad'; }, { errorReturnValue: 42, debug: printer });
        assert.strictEqual(error, 'bad');
        assert.strictEqual(reterror, 'bad');
    });
});

describe('safeAwait', function () {
    async function func1(arg) {
        if (arg) return 42;
        throw 'Argument is false';
    }

    function func2(arg) {
        if (arg) return Promise.resolve(42);
        return Promise.reject('Argument is false');
    }

    it('returns value (async function)', async function () {
        assert.deepStrictEqual(await safe.safeAwait(func1.bind(null, true)), [null,42]);
    });

    it('returns value (async promise)', async function () {
        assert.deepStrictEqual(await safe.safeAwait(func1(true)), [null,42]);
    });

    it('returns error (async function)', async function () {
        assert.deepStrictEqual(await safe.safeAwait(func1.bind(null, false)), ['Argument is false']);
    });

    it('returns error (async promise)', async function () {
        assert.deepStrictEqual(await safe.safeAwait(func1(false)), ['Argument is false']);
    });

    it('returns value (promise)', async function () {
        assert.deepStrictEqual(await safe.safeAwait(func2.bind(null, true)), [null,42]);
    });

    it('returns error (promise)', async function () {
        assert.deepStrictEqual(await safe(func2.bind(null, false)), ['Argument is false']);
    });
});
